import sys
import re
from typing import List, Tuple, Optional

def parse_ping_output(lines: List[str]) -> dict:
    summary_pattern = re.compile(r'rtt min/avg/max/mdev = ([\d.]+)/([\d.]+)/([\d.]+)/([\d.]+) ms')
    packet_loss_pattern = re.compile(r'(\d+)% packet loss')
    rtts = []
    packet_loss = None
    avg_rtt = None

    for line in lines:
        # Extract RTT values from summary line
        summary_match = summary_pattern.search(line)
        if summary_match:
            avg_rtt = float(summary_match.group(2))

        # Extract packet loss percentage
        loss_match = packet_loss_pattern.search(line)
        if loss_match:
            packet_loss = int(loss_match.group(1))

    return {
        'packet_loss_percent': packet_loss,
        'average_rtt_ms': avg_rtt,
        'rtt_values': rtts
    }

def detect_anomalies(rtts: List[float], threshold: float = 3.0) -> List[dict]:
    if not rtts or len(rtts) < 2:
        return []

    mean_rtt = sum(rtts) / len(rtts)
    anomalies = []

    for i, rtt in enumerate(rtts):
        if abs(rtt - mean_rtt) > threshold * (sum((x - mean_rtt) ** 2 for x in rtts) / len(rtts)) ** 0.5:
            anomalies.append({
                'index': i,
                'rtt': rtt,
                'deviation_from_mean': rtt - mean_rtt
            })

    return anomalies

