import sys
import re
from statistics import mean

def parse_ping_output(input_stream):
    packets_sent = packets_received = packet_loss = 0
    rtts = []

    # Regex patterns
    summary_pattern = re.compile(r'(\d+) packets transmitted, (\d+) received.*?packet loss = ([\d.]+)%')
    rtt_pattern = re.compile(r'time=([\d.]+) ms')

    for line in input_stream:
        line = line.strip()

        # Match summary line (e.g., from ping -c N)
        match = summary_pattern.search(line)
        if match:
            packets_sent = int(match.group(1))
            packets_received = int(match.group(2))
            packet_loss = float(match.group(3))

        # Match individual RTT lines
        rtt_match = rtt_pattern.search(line)
        if rtt_match:
            try:
                rtt = float(rtt_match.group(1))
                rtts.append(rtt)
            except ValueError:
                continue

    return {
        'packets_sent': packets_sent,
        'packets_received': packets_received,
        'packet_loss_percent': packet_loss,
        'rtts': rtts
    }

def detect_anomalies(rtts, threshold_factor=2.0):
    if not rtts or len(rtts) < 2:
        return {'outliers': [], 'threshold_used': None}

    avg_rtt = mean(rtts)
    stdev = (sum((x - avg_rtt) ** 2 for x in rtts) / len(rtts)) ** 0.5
    threshold = avg_rtt + (threshold_factor * stdev)

    outliers = [rtt for rtt in rtts if rtt > threshold]

    return {
        'outliers': outliers,
        'threshold_used': round(threshold, 2),
        'mean_rtt': round(avg_rtt, 2),
        'std_dev': round(stdev, 2)
    }

def main():
    data = parse_ping_output(sys.stdin)

    if data['rtts']:
        anomalies = detect_anomalies(data['rtts'])
        avg_rtt = mean(data['rtts'])
    else:
        anomalies = {'outliers': [], 'threshold_used': None}
        avg_rtt = None

    result = {
        'average_response_time_ms': round(avg_rtt, 2) if avg_rtt else None,
        'packet_loss_percent': data['packet_loss_percent'],
        'packets_sent': data['packets_sent'],
        'packets_received': data['packets_received'],
        'anomalies': {
            'outlier_count': len(anomalies['outliers']),
            'outlier_rtts': anomalies['outliers'],
            'threshold_used_ms': anomalies['threshold_used']
        }
    }

    print(result)

if __name__ == '__main__':
    main()
